// ── Selector ──────────────────────────────────────────────────────────────────
export function getParticleEntry(type) {
    return PARTICLE_CATALOG.find(p => p.type === type) ?? PARTICLE_CATALOG[0];
}
/**
 * Select the particle system type for a genome.
 * Returns "none" when no particle system is appropriate.
 */
export function selectParticleSystem(opts) {
    const { philosophy, physics, fx, sector, entropy, complexity, hasWebGL } = opts;
    if (!hasWebGL)
        return "none";
    if (entropy < 0.30)
        return "none";
    if (philosophy === "minimalist" || philosophy === "swiss_grid")
        return "none";
    // Physics-driven priority
    if (physics === "particle")
        return entropy > 0.5 ? "noise_field" : "ambient_float";
    if (physics === "magnetic")
        return "magnetic_swarm";
    // Sector-driven
    if (sector === "fintech" || sector === "saas")
        return "data_stream";
    // fx-driven
    if (fx === "audio_reactive" && entropy > 0.6)
        return "reactive_audio";
    // General
    if (entropy > 0.5 && complexity > 0.4)
        return "constellation";
    if (entropy > 0.35)
        return "ambient_float";
    return "none";
}
